import React, { useState, useEffect } from 'react';
import { X, Cpu } from 'lucide-react';
import { createSensor, updateSensor, getDistricts } from '../../api';
import { usePanchayat } from '../../context/PanchayatContext';

const SENSOR_TYPES = ['Temp', 'WaterPH', 'Humidity', 'SoilMoisture', 'Rainfall', 'WaterLevel', 'AirQuality', 'Light'];
const SENSOR_STATUSES = ['active', 'inactive', 'faulty'];

export default function SensorFormModal({ data, panchayatId, villagers, onClose, onSaved }) {
  const isEdit = !!data;
  const { selectedDistrict } = usePanchayat();

  const [form, setForm] = useState({
    id: data?.id || '',
    name: data?.name || '',
    type: data?.type || 'Temp',
    status: data?.status || 'active',
    location_description: data?.location_description || '',
    villager_id: data?.villager_id || '',
    district_id: data?.district_id || selectedDistrict?.id || '',
  });
  const [districts, setDistricts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    getDistricts().then(setDistricts).catch(() => {});
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.id.trim()) return setError('Sensor ID is required');
    if (!form.district_id) return setError('District is required');
    setLoading(true);
    setError('');
    try {
      const payload = {
        ...form,
        villager_id: form.villager_id || null,
        panchayat_id: panchayatId,
      };
      if (isEdit) {
        await updateSensor(data.id, payload);
      } else {
        await createSensor(payload);
      }
      onSaved();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to save sensor');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4">
      <div className="bg-gray-900 border border-gray-700 rounded-xl w-full max-w-md max-h-[90vh] overflow-y-auto fade-in-up">
        <div className="flex items-center justify-between px-5 py-4 border-b border-gray-800 sticky top-0 bg-gray-900">
          <h2 className="text-base font-semibold text-white flex items-center gap-2">
            <Cpu className="w-4 h-4 text-green-400" />
            {isEdit ? 'Edit Sensor' : 'Add Sensor'}
          </h2>
          <button onClick={onClose} className="text-gray-500 hover:text-white">
            <X className="w-4 h-4" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-4">
          {error && (
            <div className="text-sm text-red-400 bg-red-900/20 border border-red-800/50 rounded-lg px-3 py-2">
              {error}
            </div>
          )}

          <div>
            <label className="label">Sensor ID * <span className="text-gray-600">(unique identifier)</span></label>
            <input
              type="text"
              value={form.id}
              onChange={e => setForm(f => ({ ...f, id: e.target.value }))}
              className="input-field font-mono"
              placeholder="e.g., SENSOR_001"
              required
              disabled={isEdit}
            />
          </div>

          <div>
            <label className="label">Display Name</label>
            <input
              type="text"
              value={form.name}
              onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
              className="input-field"
              placeholder="e.g., Field Temperature Sensor"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="label">Sensor Type *</label>
              <select
                value={form.type}
                onChange={e => setForm(f => ({ ...f, type: e.target.value }))}
                className="input-field"
                required
              >
                {SENSOR_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div>
              <label className="label">Status</label>
              <select
                value={form.status}
                onChange={e => setForm(f => ({ ...f, status: e.target.value }))}
                className="input-field"
              >
                {SENSOR_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="label">District * <span className="text-gray-600">(for InfluxDB table)</span></label>
            <select
              value={form.district_id}
              onChange={e => setForm(f => ({ ...f, district_id: e.target.value }))}
              className="input-field"
              required
            >
              <option value="">Select District</option>
              {districts.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
            </select>
          </div>

          <div>
            <label className="label">Assigned Villager <span className="text-gray-600">(optional – leave empty for common sensor)</span></label>
            <select
              value={form.villager_id}
              onChange={e => setForm(f => ({ ...f, villager_id: e.target.value }))}
              className="input-field"
            >
              <option value="">Common Panchayat Sensor</option>
              {villagers.map(v => <option key={v.id} value={v.id}>{v.name}</option>)}
            </select>
          </div>

          <div>
            <label className="label">Location Description</label>
            <textarea
              value={form.location_description}
              onChange={e => setForm(f => ({ ...f, location_description: e.target.value }))}
              className="input-field resize-none"
              placeholder="Where is this sensor physically located?"
              rows={2}
            />
          </div>

          <div className="flex items-center gap-3 pt-1">
            <button type="button" onClick={onClose} className="btn-secondary flex-1">Cancel</button>
            <button type="submit" disabled={loading} className="btn-primary flex-1 flex items-center justify-center gap-2 disabled:opacity-60">
              {loading ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : null}
              {isEdit ? 'Update' : 'Add Sensor'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
